class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int max_len = 0, count = 0, zeros = 0;
        for (char c : s) {
            if (c == '0') {
                zeros++;
            } else {
                count++;
                if (count < zeros) {
                    max_len = max(max_len, zeros + count);
                } else {
                    max_len = max(max_len, count + zeros);
                }
            }
        }
        return max_len;
    }
};
```

